mapper.select:
select distinct mp.permission
from user_role ur
         inner join role_menu rm on ur.role_id = rm.role_id
         inner join menu_permission mp on rm.menu_permission_id = mp.menu_permission_id
where ur.user_id = #{userId}
  and mp.biz_type = #{sysType}

select uri, method, permission
from menu_permission
where biz_type = #{sysType}
